/* ============================================================
 * HELPER FUNCTIONS
 * ============================================================ */

/**
 * @brief Create a linked list from the chord data array
 * @return Pointer to head of linked list, or NULL on failure
 */
ChordNode_t* viva_create_linked_list(void) {
    if (VIVA_TOTAL_EVENTS == 0) return NULL;

    ChordNode_t* head = (ChordNode_t*)malloc(sizeof(ChordNode_t));
    if (!head) return NULL;

    head->event = viva_data[0];
    head->next = NULL;

    ChordNode_t* current = head;
    for (uint32_t i = 1; i < VIVA_TOTAL_EVENTS; i++) {
        ChordNode_t* node = (ChordNode_t*)malloc(sizeof(ChordNode_t));
        if (!node) {
            viva_free_linked_list(head);
            return NULL;
        }
        node->event = viva_data[i];
        node->next = NULL;
        current->next = node;
        current = node;
    }

    return head;
}

/**
 * @brief Free a linked list created by create_linked_list
 * @param head Pointer to head of linked list
 */
void viva_free_linked_list(ChordNode_t* head) {
    while (head) {
        ChordNode_t* next = head->next;
        free(head);
        head = next;
    }
}

/**
 * @brief Get total playback duration in milliseconds
 * @return Total duration in ms
 */
uint32_t viva_get_total_duration_ms(void) {
    uint32_t total = 0;
    for (uint32_t i = 0; i < VIVA_TOTAL_EVENTS; i++) {
        total += viva_data[i].delay_to_next_ms;
    }
    if (VIVA_TOTAL_EVENTS > 0) {
        total += viva_data[VIVA_TOTAL_EVENTS - 1].duration_ms;
    }
    return total;
}
